mapper.select:
/*FathMapper.getFathSelfUrl*/
SELECT  URL.RES_NO
        ,URL.OPER_TYPE
        ,TO_CHAR(URL.EXPIR_DT, 'YYYYMMDDHH24MISS') AS EXPIR_DT
FROM    NMCP_FATH_SELF_URL URL
WHERE   URL.UUID = #{uuid}

mapper.update:
/* FathMapper.updateFathCmpltNtfyDt */
UPDATE  MCP_REQUEST
SET     FATH_CMPLT_NTFY_DT  = #{fathCmpltNtfyDt},
        RVISN_ID  		    = 'SELF',
        RVISN_DTTM          = SYSDATE
WHERE 	RES_NO              = #{resNo}

UPDATE  MCP_REQUEST_OSST
SET     MVNO_ORD_NO = LPAD(#{resNo}, 14, '0')
WHERE   MVNO_ORD_NO = #{tempResNo}

/* FathMapper.updateNameChgFathSkip */
UPDATE NMCP_CUST_REQUEST_NAME_CHG SET
    MCN_STATE_CODE = '08',
    RVISN_ID = 'SELF',
    RVISN_DTTM = SYSDATE
WHERE MCN_RES_NO = #{resNo}
